/// <summary>
/// assign system date to transdate
/// </summary>
/// <param name = "_append">boolean</param>
public void create(boolean _append = true)
{
    super(_append);

    ETGBinJournalLine.TransDate = systemDateGet();
    ETGBinJournalLine_ds.refresh();

}

/// <summary>
/// enable/disable control
/// </summary>
/// <returns>integer</returns>
public int active()
{
    int ret;
    boolean  Configenable,Sizeenable,ColorEnable,Styleenable;
    EcoResProductDimensionGroupProduct      erpdgp;
    EcoResProductDimensionGroup             erpdg;
    InventJournalTable                      inventJournalTable;

    ret = super();

    erpdgp=EcoResProductDimensionGroupProduct::findByProduct(InventTable::find(ETGBinJournalLine.ItemId).Product);
    erpdg=EcoResProductDimensionGroup::find(erpdgp.ProductDimensionGroup);

    Configenable = ETGGlobal::checkdimactive(ETGBinJournalLine.ItemId,'Configid',erpdg.Name);
    Sizeenable  =  ETGGlobal::checkdimactive(ETGBinJournalLine.ItemId,'InventSizeId',erpdg.Name);
    ColorEnable =  ETGGlobal::checkdimactive(ETGBinJournalLine.ItemId,'Inventcolorid',erpdg.Name);
    Styleenable =  ETGGlobal::checkdimactive(ETGBinJournalLine.ItemId,'InventStyleId',erpdg.Name);

    ETGBinJournalLine_ds.object(fieldNum(ETGBinJournalLine,Configuration)).allowEdit(Configenable);
    ETGBinJournalLine_ds.object(fieldNum(ETGBinJournalLine,Colour)).allowEdit(ColorEnable);
    ETGBinJournalLine_ds.object(fieldNum(ETGBinJournalLine,Size)).allowEdit(Sizeenable);
    ETGBinJournalLine_ds.object(fieldNum(ETGBinJournalLine,Style)).allowEdit(Styleenable);

    ETGBinJournalLine_ds.object(fieldNum(ETGBinJournalLine,RetailVariantId)).allowEdit(Configenable||Sizeenable||ColorEnable||Styleenable);

    boolean  batchenable,serailenable;

    batchenable=   ecoResTrackingDimensionGroupFldSetup::findByDimensionGroupFieldId(InventTable::find(ETGBinJournalLine.ItemId).trackingDimensionGroup(), fieldNum(InventDim, InventBatchId)).IsActive;
    ETGBinJournalLine_ds.object(fieldNum(ETGBinJournalLine,ToBatch)).allowEdit(batchenable);

    serailenable=   ecoResTrackingDimensionGroupFldSetup::findByDimensionGroupFieldId(InventTable::find(ETGBinJournalLine.ItemId).trackingDimensionGroup(), fieldNum(InventDim,InventSerialId)).IsActive;
    ETGBinJournalLine_ds.object(fieldNum(ETGBinJournalLine,InventSerialId)).allowEdit(serailenable);

    TransferGRNCreate.enabled(ETGBinJournalLine.TransferJRNId == "");
    SelectGRN.enabled(ETGBinJournalLine.TransferJRNId == "");
    GP1.allowEdit(ETGBinJournalLine.TransferJRNId == "");
    GP2.allowEdit(ETGBinJournalLine.TransferJRNId == "");
    ETGBinJournalLine_ds.allowDelete(ETGBinJournalLine.TransferJRNId == "");

    ETGBinJournalLine_ds.object(fieldNum(ETGBinJournalLine,Port)).allowEdit(ETGBinJournalLine.BinLineLocked == NoYes::No);
    ETGBinJournalLine_ds.object(fieldNum(ETGBinJournalLine,ProcessingPlant)).allowEdit(ETGBinJournalLine.BinLineLocked == NoYes::No);
    ETGBinJournalLine_ds.object(fieldNum(ETGBinJournalLine,ProcessingStartDate)).allowEdit(ETGBinJournalLine.BinLineLocked == NoYes::No);
    ETGBinJournalLine_ds.object(fieldNum(ETGBinJournalLine,ProcessingEndDate)).allowEdit(ETGBinJournalLine.BinLineLocked == NoYes::No);
    ETGBinJournalLine_ds.object(fieldNum(ETGBinJournalLine,Waste)).allowEdit(ETGBinJournalLine.BinLineLocked == NoYes::No);

    select firstonly inventJournalTable
        where inventJournalTable.JournalId == ETGBinJournalLine.TransferJRNId
        && inventJournalTable.Posted == NoYes::Yes;

    if (inventJournalTable.RecId)
    {
        this.formRun().design().controlName(formControlStr(ETGBinJournalLine, ETGBinLotLine)).enabled(true);
        this.formRun().design().controlName(formControlStr(ETGBinJournalLine, WeightAdjustment)).enabled(true);
    }

    else
    {
        this.formRun().design().controlName(formControlStr(ETGBinJournalLine, ETGBinLotLine)).enabled(false);
        this.formRun().design().controlName(formControlStr(ETGBinJournalLine, WeightAdjustment)).enabled(false);
    }

    return ret;
}

/// <summary>
/// modifies controls upon modification of BinQty
/// </summary>
public void modified()
{
    super();
    ETGBinJournalLine.DiffereceQty = ETGBinJournalLine.BinQty - ETGBinJournalLine.FGRNQty;
}

/// <summary>
/// lookup method for name.
/// </summary>
/// <param name = "_formControl">EcoResColor</param>
/// <param name = "_filterStr">Name</param>
public void lookup(FormControl _formControl, str _filterStr)
{
    // super(_formControl, _filterStr);

    Query                   query = new Query();
    QueryBuildDataSource    queryBuildDataSource;
    SysTableLookup          sysTableLookup;


    sysTableLookup = SysTableLookup::newParameters(tableNum(EcoResColor), _formControl);
    queryBuildDataSource = query.addDataSource(tableNum(EcoResColor));
    sysTableLookup.addLookupField(fieldNum(EcoResColor, Name));

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}

