/// <summary>
/// sends arguments to another form
/// </summary>
public void clicked()
{
    super();

    Args args;
    FormRun formRun;
    ;
    super();
    args = new args(formstr(ETGBinJournalGRNSelection)); // sending Args(record) to FormB
    args.record(ETGBinJournalLine);
    formrun = classfactory.formrunclass(args);
    formrun.init();
    formrun.run();
    formrun.wait();
    formrun.detach();

}

/// <summary>
/// creates transfer journal
/// </summary>
public void clicked()
{

    if(ETGBinJournalLine.RetailvariantId == '')
    {
        throw error(strFmt('@ETGReport:VariantIdValidation'));
    }

    if(ETGBinJournalLine.SiteId == '')
    {
        throw error(strFmt('@ETGReport:SiteIdvalidation'));
    }

    if(ETGBinJournalLine.Warehouse == '')
    {
        throw error(strFmt('@ETGReport:WarehouseValidation'));
    }

    if(ETGBinJournalLine.Location == '')
    {
        throw error(strFmt('@ETGReport:LocationValidation'));
    }

    if(ETGBinJournalLine.ToBatch == '')
    {
        throw error(strFmt('@ETGReport:ToBatchValidation'));
    }

    if(InventParameters::find().ETGBinTransferJournalName == '')
    {
        throw error(strFmt('%1','@ETGReport:DefineJournalNameInInventoryParameters'));
    }

    super();

    if (box::yesNo('@ETGReport:BinJournalCreationConfirmation', dialogButton::Yes, '@ETGReport:Confirmation') == dialogButton::Yes)
    {
        ETGGlobal::CreateTransferJournal(ETGBinJournalLine.RecId);
        ETGBinJournalLine_ds.research(true);
    }
}

/// <summary>
///
/// </summary>
public void clicked()
{


    if(InventJournalTable::find(ETGBinJournalLine.TransferJRNId).Posted == NoYes::No)
    {
        throw error(strFmt('%1','Atleast one Bin Transfer Journal has been created and Posted required.'));
    }

    super();
}

